// --- Długi blok tekstu: case studies i rozbudowane treści ---
function deepTextBlock1() {
    const txt = [];
    txt.push(`Przykład 1 — defenzyna drabinka: Jan ma 40 000 PLN i chce bezpiecznie zarabiać, jednocześnie zachowując dostęp do części kapitału co roku. Tworzy drabinkę: 10k na 1 rok, 10k na 3 lata, 10k na 5 lat, 10k na 10 lat. Każdego roku jedna z krótszych obligacji dojrzewa — Jan reinwestuje część lub całość środków w nową serię na 10 lat lub w krótszą, zależnie od sytuacji rynkowej.`);
    txt.push(`Przykład 2 — ochrona przed inflacją: Maria inwestuje głównie w obligacje indeksowane inflacją, bo oczekuje, że inflacja w najbliższych latach utrzyma się powyżej stopy nominalnej rynku. Jej cel to zachowanie siły nabywczej przy umiarkowanym realnym zysku.`);
    txt.push(`Przykład 3 — agresywnie konserwatywny: Piotr łączy obligacje korporacyjne o wyższej stopie z bezpiecznymi obligacjami skarbowymi, obniżając ogólne ryzyko kredytowe przez dywersyfikację emitentów.`);
    txt.push(`Wnioski: każdy przykład ma inną tolerancję ryzyka, inne potrzeby płynności i oczekiwania inflacyjne. Nie ma uniwersalnej recepty — są ramy, które możesz dopasować do siebie.`);
    txt.push(`W praktyce warto robić proste symulacje i zapisywać rezultaty — to pomaga zauważyć, które reguły działają w Twoim portfelu, a które są tylko teorią.`);
    return txt;
}
function deepTextBlock2() {
    const txt = [];
    txt.push(`Reguły psychologiczne: 1) Zapisz reguły, zanim zainwestujesz. 2) Nie reaguj na każdy nagłówek w mediach. 3) Rebalancuj mechanicznie — to zmniejsza wpływ emocji.`);
    txt.push(`Kilka praktycznych reguł: trzymaj w gotówce równowartość kilku miesięcznych wydatków; jeśli obligacje stanowią dużą część Twojego portfela, miej plan co robić przy nagłym wzroście stóp procentowych.`);
    txt.push(`Zrozum, że "bezpieczeństwo" ma różne twarze: stabilność nominalna vs stabilność realna (po uwzględnieniu inflacji). Twoje priorytety decydują o wyborze instrumentów.`);
    txt.push(`Na koniec: traktuj ten poradnik jako narzędzie — eksperymentuj małymi kwotami, analizuj wyniki i skonsultuj się z doradcą, jeżeli planujesz większe alokacje.`);
    return txt;
}
